SELECT COALESCE(SUM(invoices_total),0) AS invoices_total, COALESCE(SUM(completed),0) AS completed, COALESCE(SUM(failed),0) AS failed, COALESCE(SUM(needs_mapping),0) AS needs_mapping, COALESCE(SUM(needs_review),0) AS needs_review, ROUND(AVG(avg_processing_ms))::int AS avg_processing_ms
FROM ops_metrics_daily
WHERE metric_date = '{{$('Build Yesterday Range').item.json.metric_date}}'::date;

