const totals = $json || {};
const failItems = $items('Top Failures').map(i => i.json);
const failText = failItems.length ? failItems.map((f, idx) => `${idx + 1}. ${String(f.error_type).slice(0, 60)}: ${f.total}`).join('\n') : '- none';
const metricDate = $('Build Yesterday Range').item.json.metric_date;
const text = [
  `📊 Daily Ops Summary (${metricDate})`,
  `Invoices: ${totals.invoices_total || 0}`,
  `Completed: ${totals.completed || 0}`,
  `Failed: ${totals.failed || 0}`,
  `Needs mapping: ${totals.needs_mapping || 0}`,
  `Needs review: ${totals.needs_review || 0}`,
  `Avg processing (ms): ${totals.avg_processing_ms || 0}`,
  `Top failures:`,
  failText
].join('\n');

return [{ json: { summary_text: text.slice(0, 3500), metric_date: metricDate } }];
